#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int numVertices;
    int** adjMatrix;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adjMatrix = (int**) malloc(numVertices * sizeof(int*));
    for (int i = 0; i < numVertices; i++) {
        graph->adjMatrix[i] = (int*) malloc(numVertices * sizeof(int));
        for (int j = 0; j < numVertices; j++) {
            graph->adjMatrix[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    graph->adjMatrix[src][dest] = 1;
}

// Function to perform topological sort
void topologicalSort(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    int* stack = (int*) malloc(graph->numVertices * sizeof(int));
    int top = -1;
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph->numVertices; i++) {
        if (!visited[i]) {
            topologicalSortUtil(graph, i, visited, stack, &top);
        }
    }
    printf("Topological Sort: ");
    while (top != -1) {
        printf("%d ", stack[top--]);
    }
    printf("\n");
}

// Utility function for topological sort
void topologicalSortUtil(Graph* graph, int vertex, int* visited, int* stack, int* top) {
    visited[vertex] = 1;
    for (int i = 0; i < graph->numVertices; i++) {
        if (graph->adjMatrix[vertex][i] && !visited[i]) {
            topologicalSortUtil(graph, i, visited, stack, top);
        }
    }
    stack[++(*top)] = vertex;
}

int main() {
    int numVertices = 4;
    Graph* graph = createGraph(numVertices);
    addEdge(graph, 1, 0);
    addEdge(graph, 2, 0);
    addEdge(graph, 3, 1);
    addEdge(graph, 3, 2);
    topologicalSort(graph);
    return 0;
}

